")\n}\n\nmodel SubActivities {\n  subActivitiesId String    @id @default(uuid())\n  activityId      String?\n  activity        Activity? @relation(fields: [activityId], references: [activityId])\n  description     String?\n  activityDate    DateTime?\n\n  @@map(\"subactivities\")\n}\n\nmodel ActivityReport {\n  activityReportId     String    @id @default(uuid())\n  activity             Activity? @relation(fields: [activityId], references: [activityId])\n  activityId           String?\n  percentageCompletion Int?\n  actualStartDate      DateTime?\n  actualEndDate        DateTime?\n  actualCost           Int?\n  actualNarrative      String?\n  createAt             DateTime? @default(now())\n  updateAt             DateTime? @default(now())\n\n  @@map(\"activityreport\")\n}\n\n// LOGICAL FRAMEWORK\nmodel LogicalFramework {\n  logicalFrameworkId String    @id @default(uuid())\n  project            Project?  @relation(fields: [projectId], references: [projectId])\n  projectId          String?\n  documentName       String?\n  documentURL        String?\n  createAt           DateTime? @default(now())\n  updateAt           DateTime? @default(now())\n\n  @@map(\"logicalframework\")\n}\n\n// REQUEST\nmodel Request {\n  requestId                  String       @id @default(uuid())\n  staff                      String?\n  output                     Output?      @relation(fields: [outputId], references: [outputId])\n  outputId                   String?\n  activityTitle              String?\n  activityBudgetCode         Int?\n  activityLocation           String?\n  activityPurposeDescription String?\n  activityStartDate          DateTime?\n  activityEndDate            DateTime?\n  budgetCode                 Int?\n  modeOfTransport            String?\n  driverName                 String?\n  driversPhoneNumber         String?\n  vehiclePlateNumber         String?\n  vehicleColor               String?\n  departureTime              DateTime?\n  route                      String?\n  recipientPhoneNumber       String?\n  documentName               String?\n  documentURL                String?\n  project                    Project?     @relation(fields: [projectId], references: [projectId])\n  projectId                  String?\n  approval_A                 Int?\n  approval_B                 Int?\n  approval_C                 Int?\n  approval_D                 Int?\n  approvedBy_A               String?      @db.VarChar(191)\n  approvedBy_B               String?      @db.VarChar(191)\n  approvedBy_C               String?      @db.VarChar(191)\n  approvedBy_D               String?      @db.VarChar(191)\n  comment_A                  String?\n  comment_B                  String?\n  comment_C                  String?\n  comment_D                  String?\n  status                     String?\n  createAt                   DateTime?    @default(now())\n  updateAt                   DateTime?    @default(now())\n  user                       User?        @relation(fields: [createdBy], references: [userId])\n  createdBy                  String?\n  retirement                 Retirement[]\n  lineItems                  LineItem[]\n\n  @@map(\"request\")\n}\n\nmodel LineItem {\n  lineItemId  String    @id @default(uuid())\n  requestId   String\n  request     Request   @relation(fields: [requestId], references: [requestId])\n  activity    Activity? @relation(fields: [activityId], references: [activityId])\n  activityId  String?\n  description String?\n  quantity    Int?\n  frequency   Int?\n  unitCost    Int?\n  totalBudget Int?\n  totalSpent  Int?\n  variance    Int?\n  createAt    DateTime? @default(now())\n  updateAt    DateTime? @default(now())\n\n  @@map(\"lineitem\")\n}\n\n//Retirement\nmodel Retirement {\n  retirementId            String    @id @default(uuid())\n  activityLineDescription String?\n  quantity                Int?\n  frequency               Int?\n  unitCost                Int?\n  actualCost              Int?\n  totalBudget             Int?\n  documentName            String?\n  documentURL             String?\n  approval_A              Int?\n  approval_B              Int?\n  approval_C              Int?\n  approvedBy_A            String?   @db.VarChar(191)\n  approvedBy_B            String?   @db.VarChar(191)\n  approvedBy_C            String?   @db.VarChar(191)\n  comment_A               String?\n  comment_B               String?\n  comment_C               String?\n  request                 Request?  @relation(fields: [requestId], references: [requestId])\n  requestId               String?\n  status                  String?\n  user                    User?     @relation(fields: [createdBy], references: [userId])\n  createdBy               String?\n  createAt                DateTime? @default(now())\n  updateAt                DateTime? @default(now())\n\n  @@map(\"retirement\")\n}\n\n// REPORT\nmodel Report {\n  reportId   String @id @default(uuid())\n  reportName String\n  reportType String // \"Activity Summary\", \"Financial Overview\", \"Request Analysis\", \"Retirement Analysis\"\n\n  // Filter parameters used\n  project         Project?  @relation(fields: [projectId], references: [projectId])\n  projectId       String?\n  startDate       DateTime?\n  endDate         DateTime?\n  selectedMetrics String?   @db.Text // JSON array of selected metrics\n\n  // Report metadata\n  generatedBy String? // User ID who generated the report\n  fileUrl     String? // Path to generated PDF file\n  fileSize    Int? // File size in bytes\n  status      String? // \"Generating\", \"Completed\", \"Failed\"\n\n  // Analytics summary (stored for quick access)\n  totalActivities   Int?\n  totalRequests     Int?\n  totalRetirements  Int?\n  budgetUtilization Float?\n\n  createAt DateTime @default(now())\n  updateAt DateTime @default(now())\n\n  @@map(\"report\")\n}\n"
